ucs.kql:
// Volt Typhoon — LOTL recon burst (4+ native discovery bins under one shell within 5 min).
// Parents include common Volt Typhoon web-shell hosts (w3wp, tomcat, ManageEngine, java) — the actor
// pivots from internet-facing exploits (Fortinet, Citrix, ManageEngine ADSelfService Plus) into a shell.
let _lookback = 7d;
let _bucket = 5m;
let _recon_bins = dynamic([
    "net.exe","net1.exe","netstat.exe","tasklist.exe","systeminfo.exe","whoami.exe",
    "ipconfig.exe","query.exe","quser.exe","nltest.exe","wmic.exe","ping.exe",
    "arp.exe","route.exe","reg.exe","hostname.exe"
]);
let _shell_parents = dynamic([
    "cmd.exe","powershell.exe","pwsh.exe",
    // web-shell / exploit-chain pivot points seen in Volt Typhoon ops
    "w3wp.exe","httpd.exe","tomcat9.exe","java.exe","sqlservr.exe",
    "manageengineservicedesk.exe","fortiwebd.exe"
]);
DeviceProcessEvents
| where Timestamp > ago(_lookback)
| where AccountName !endswith "$"
| where FileName in~ (_recon_bins)
| where InitiatingProcessFileName in~ (_shell_parents)
| summarize ReconBinsCount = dcount(FileName),
            ReconBins      = make_set(FileName, 32),
            CmdLines       = make_set(ProcessCommandLine, 64),
            ParentChain    = make_set(strcat(InitiatingProcessParentFileName, " -> ", InitiatingProcessFileName), 8),
            FirstSeen      = min(Timestamp),
            LastSeen       = max(Timestamp)
            by DeviceId, DeviceName, AccountName, bin(Timestamp, _bucket)
| where ReconBinsCount >= 4                       // 4+ distinct recon bins in a 5-min window
| extend BurstWindowSec = datetime_diff('second', LastSeen, FirstSeen)
| project FirstSeen, LastSeen, BurstWindowSec, DeviceName, AccountName,
          ReconBinsCount, ReconBins, ParentChain, CmdLines
| order by ReconBinsCount desc, FirstSeen desc
